} else if (sessionResetMinOnly) {
  const ms = parseInt(sessionResetMinOnly[1]) * 60 * 1000;
  sessionResetsAt = new Date(Date.now() + ms).toISOString();
} else if (sessionResetHrOnly) {
  const ms = parseInt(sessionResetHrOnly[1]) * 3600 * 1000;
  sessionResetsAt = new Date(Date.now() + ms).toISOString();
}

